# 输入获取
matrix = input().split(",")


# 并查集实现
class UnionFindSet:
    def __init__(self, n):
        self.fa = [i for i in range(n)]
        self.count = n

    def find(self, x):
        if x != self.fa[x]:
            self.fa[x] = self.find(self.fa[x])
            return self.fa[x]
        return x

    def union(self, x, y):
        x_fa = self.find(x)
        y_fa = self.find(y)

        if x_fa != y_fa:
            self.fa[y_fa] = x_fa
            self.count -= 1


# 算法入口
def getResult(matrix):
    n = len(matrix)

    ufs = UnionFindSet(n)

    for i in range(n):
        for j in range(i + 1, n):
            if matrix[i][j] == "1":
                ufs.union(i, j)

    return ufs.count


# 算法调用
print(getResult(matrix))
